create table sponsor_agreements (
    agreement_id     number generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache 20
    noorder nocycle nokeep noscale not null enable,
    sponsor_id       number not null enable,
    team_id          number not null enable,
    agreement_name   varchar2(120 byte) not null enable,
    start_date       date not null enable,
    end_date         date not null enable,
    annual_value     number(12, 2) not null enable,
    payment_terms    varchar2(40 byte),
    agreement_status varchar2(20 byte) default 'ACTIVE' not null enable
);

alter table sponsor_agreements
    add constraint agreements_dates_ck check ( end_date >= start_date ) enable;

alter table sponsor_agreements
    add constraint agreements_status_ck
        check ( agreement_status in ( 'ACTIVE', 'PENDING', 'EXPIRED', 'CANCELLED' ) ) enable;

alter table sponsor_agreements
    add constraint sponsor_agreements_pk primary key ( agreement_id )
        using index enable;


